module RefModule (
	input clk,
	input resetn,
	input load,
	input [7:0] data,
	output reg [7:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge resetn or posedge dbg_halt) begin
	if (~resetn)
		q <= 8'b0;
	else if (load)
		q <= data;
end

endmodule
